html:
{% set settings = frappe.get_doc('MC Settings') %}{% set company = frappe.get_doc('Company', settings.company) %}
{% set garantia = frappe.get_doc('Garantia', doc.garantia) %}
<style>
  .entre-mc-print { font-family: Arial, sans-serif; font-size: 11px; }
  .entre-mc-print h2 { text-align: center; margin-bottom: 2px; }
  .entre-mc-print .subtitulo { text-align: center; margin-bottom: 16px; color: #555; }
  .entre-mc-print table { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .entre-mc-print table, .entre-mc-print th, .entre-mc-print td { border: 1px solid #999; }
  .entre-mc-print th, .entre-mc-print td { padding: 4px 6px; text-align: left; }
  .entre-mc-print .secao { font-weight: bold; background: #f0f0f0; padding: 4px 6px; margin-top: 14px; }
  .entre-mc-print .assinaturas { margin-top: 40px; display: flex; justify-content: space-between; }
  .entre-mc-print .assinatura { width: 45%; text-align: center; }
  .entre-mc-print .linha { margin-top: 40px; border-top: 1px solid #000; }
</style>
<div class='entre-mc-print'>
  <h2>{{ company.company_name or '' }}</h2>
  <div class='subtitulo'>NUIT: {{ company.tax_id or '' }} | {{ company.phone_no or '' }} | {{ company.email or '' }}</div>
  <h3 style='text-align:center;'>Recibo de Quitação e Devolucao Da Garantia</h3>

  <table>
    <tr><th>Garantia</th><td>{{ doc.garantia }}</td><th>Cliente</th><td>{{ doc.cliente }}</td></tr>
    <tr><th>Data de Devolução</th><td>{{ frappe.utils.formatdate(doc.data_de_devolucao) }}</td><th>Motivo</th><td>{{ doc.motivo }}</td></tr>
  </table>

  <div class='secao'>Bens Devolvidos</div>
  <table>
    <tr><th>Nome</th><th>Categoria</th><th>Estado</th><th>Nº de Série</th></tr>
    {% for item in garantia.itens %}
    <tr>
      <td>{{ item.nome }}</td>
      <td>{{ item.categoria or '' }}</td>
      <td>{{ item.estado or '' }}</td>
      <td>{{ item.numero_de_serie or '' }}</td>
    </tr>
    {% endfor %}
  </table>

  <p style='margin-top:16px;'>Declara-se, para os devidos efeitos, que o crédito associado à presente garantia se encontra totalmente liquidado, pelo que os bens acima identificados são devolvidos ao Cliente nesta data, nada mais havendo a reclamar entre as partes.</p>

  <div class='assinaturas'>
    <div class='assinatura'>
      <div class='linha'></div>
      <p>O Cliente<br>Data: ____/____/________</p>
    </div>
    <div class='assinatura'>
      <div class='linha'></div>
      <p>{{ company.company_name or '' }}<br>Data: ____/____/________</p>
    </div>
  </div>
</div>
